mapper.select:
SELECT m.*, s.site_nm, cd_gr.code_label AS grade_cd_nm, cd_ms.code_label AS member_status_cd_nm FROM mb_member m LEFT JOIN sy_site s ON s.site_id = m.site_id LEFT JOIN sy_code cd_gr ON cd_gr.code_grp = 'MEMBER_GRADE' AND cd_gr.code_value = m.grade_cd LEFT JOIN sy_code cd_ms ON cd_ms.code_grp = 'MEMBER_STATUS' AND cd_ms.code_value = m.member_status_cd
ORDER BY m.member_id ASC ORDER BY m.member_id DESC ORDER BY m.member_nm ASC ORDER BY m.member_nm DESC ORDER BY m.join_date ASC ORDER BY m.join_date DESC ORDER BY m.join_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

