ORDER BY m.member_id ASC ORDER BY m.member_id DESC ORDER BY m.member_nm ASC ORDER BY m.member_nm DESC ORDER BY m.join_date ASC ORDER BY m.join_date DESC ORDER BY m.join_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

